/// <summary>
/// Method to find sales agreement based on parent deal number.
/// </summary>
/// <returns>
/// sales agreement based on parent deal number.
/// </returns>
public static SalesAgreementHeader ETG_findByParentDealNumber(str _parentDealNumber,
                                        boolean              _forUpdate = false)
{
    SalesAgreementHeader salesAgreementHeader;

    if (_parentDealNumber)
    {
        if (_forUpdate)
        {
            salesAgreementHeader.selectForUpdate(_forUpdate);
        }

        select salesAgreementHeader
            where salesAgreementHeader.ETGDMSDealNumber == _parentDealNumber;
    }

    return salesAgreementHeader;
}
